406:         // padding described by this Transform
407:         int supportsModePadding(Service s) {
408:             int smode = supportsMode(s);
409:             if (smode == S_NO) {
410:                 return smode;
411:             }
412:             int spad = supportsPadding(s);
413:             // our constants are defined so that Math.min() is a tri-valued AND
414:             return Math.min(smode, spad);
415:         }
