417:         // separate methods for mode and padding
418:         // called directly by cipher only to throw the correct exception
419:         int supportsMode(Service s) {
420:             return supports(s, ATTR_MODE, mode);
421:         }
422:         int supportsPadding(Service s) {
423:             return supports(s, ATTR_PAD, pad);
