426:         private static int supports(Service s, String attrName, String value) {
427:             if (value == null) {
428:                 return S_YES;
429:             }
430:             String regexp = s.getAttribute(attrName);
431:             if (regexp == null) {
432:                 return S_MAYBE;
433:             }
434:             return matches(regexp, value) ? S_YES : S_NO;
435:         }
436: 
437:         // ConcurrentMap<String,Pattern> for previously compiled patterns
438:         private static final ConcurrentMap<String, Pattern> patternCache =
439:             new ConcurrentHashMap<String, Pattern>();
440: 
441:         private static boolean matches(String regexp, String str) {
442:             Pattern pattern = patternCache.get(regexp);
443:             if (pattern == null) {
444:                 pattern = Pattern.compile(regexp);
445:                 patternCache.putIfAbsent(regexp, pattern);
446:             }
447:             return pattern.matcher(str.toUpperCase(Locale.ENGLISH)).matches();
448:         }
