452:     private static List<Transform> getTransforms(String transformation)
453:             throws NoSuchAlgorithmException {
454:         String[] parts = tokenizeTransformation(transformation);
455: 
456:         String alg = parts[0];
457:         String mode = parts[1];
458:         String pad = parts[2];
459: 
460:         if ((mode.length() == 0) && (pad.length() == 0)) {
461:             // Algorithm only
462:             Transform tr = new Transform(alg, "", null, null);
463:             return Collections.singletonList(tr);
464:         } else {
465:             // Algorithm w/ at least mode or padding or both
466:             List<Transform> list = new ArrayList<>(4);
467:             list.add(new Transform(alg, "/" + mode + "/" + pad, null, null));
468:             list.add(new Transform(alg, "/" + mode, null, pad));
469:             list.add(new Transform(alg, "//" + pad, mode, null));
470:             list.add(new Transform(alg, "", mode, pad));
471:             return list;
472:         }
473:     }
