475:     // get the transform matching the specified service
476:     private static Transform getTransform(Service s,
477:                                           List<Transform> transforms) {
478:         String alg = s.getAlgorithm().toUpperCase(Locale.ENGLISH);
479:         for (Transform tr : transforms) {
480:             if (alg.endsWith(tr.suffix)) {
481:                 return tr;
482:             }
483:         }
484:         return null;
485:     }
