487:     /**
488:      * Returns a {@code Cipher} object that implements the specified
489:      * transformation.
490:      *
491:      * <p> This method traverses the list of registered security providers,
492:      * starting with the most preferred provider.
493:      * A new {@code Cipher} object encapsulating the
494:      * {@code CipherSpi} implementation from the first
495:      * provider that supports the specified algorithm is returned.
496:      *
497:      * <p> Note that the list of registered providers may be retrieved via
498:      * the {@link Security#getProviders() Security.getProviders()} method.
499:      *
500:      * @apiNote
501:      * It is recommended to use a transformation that fully specifies the
502:      * algorithm, mode, and padding. By not doing so, the provider will
503:      * use a default for the mode and padding which may not meet the security
504:      * requirements of your application.
505:      *
506:      * @implNote
507:      * The JDK Reference Implementation additionally uses the
508:      * {@code jdk.security.provider.preferred}
509:      * {@link Security#getProperty(String) Security} property to determine
510:      * the preferred provider order for the specified algorithm. This
511:      * may be different than the order of providers returned by
512:      * {@link Security#getProviders() Security.getProviders()}.
513:      * See also the Cipher Transformations section of the {@extLink
514:      * security_guide_jdk_providers JDK Providers} document for information
515:      * on the transformation defaults used by JDK providers.
516:      *
517:      * @param transformation the name of the transformation, e.g.,
518:      * <i>AES/CBC/PKCS5Padding</i>.
519:      * See the Cipher section in the <a href=
520:      *   "{@docRoot}/../specs/security/standard-names.html#cipher-algorithms">
521:      * Java Security Standard Algorithm Names Specification</a>
522:      * for information about standard transformation names.
523:      *
524:      * @spec security/standard-names.html Java Security Standard Algorithm Names
525:      * @return a {@code Cipher} object that implements the requested
526:      * transformation
527:      *
528:      * @throws NoSuchAlgorithmException if {@code transformation}
529:      *         is {@code null}, empty, in an invalid format,
530:      *         or if no provider supports a {@code CipherSpi}
531:      *         implementation for the specified algorithm
532:      *
533:      * @throws NoSuchPaddingException if {@code transformation}
534:      *         contains a padding scheme that is not available
535:      *
536:      * @see java.security.Provider
537:      */
538:     public static final Cipher getInstance(String transformation)
539:             throws NoSuchAlgorithmException, NoSuchPaddingException
540:     {
541:         if ((transformation == null) || transformation.isEmpty()) {
542:             throw new NoSuchAlgorithmException("Null or empty transformation");
543:         }
544:         List<Transform> transforms = getTransforms(transformation);
545:         List<ServiceId> cipherServices = new ArrayList<>(transforms.size());
546:         for (Transform transform : transforms) {
547:             cipherServices.add(new ServiceId("Cipher", transform.transform));
548:         }
549:         // make sure there is at least one service from a signed provider
550:         // and that it can use the specified mode and padding
551:         Iterator<Service> t = GetInstance.getServices(cipherServices);
552:         Exception failure = null;
553:         while (t.hasNext()) {
554:             Service s = t.next();
555:             if (JceSecurity.canUseProvider(s.getProvider()) == false) {
556:                 continue;
557:             }
558:             Transform tr = getTransform(s, transforms);
559:             if (tr == null) {
560:                 // should never happen
561:                 continue;
562:             }
563:             int canuse = tr.supportsModePadding(s);
564:             if (canuse == S_NO) {
565:                 // does not support mode or padding we need, ignore
566:                 continue;
567:             }
568:             // S_YES, S_MAYBE
569:             // even when mode and padding are both supported, they
570:             // may not be used together, try out and see if it works
571:             try {
572:                 CipherSpi spi = (CipherSpi)s.newInstance(null);
573:                 tr.setModePadding(spi);
574:                 // specify null instead of spi for delayed provider selection
575:                 return new Cipher(null, s, t, transformation, transforms);
576:             } catch (Exception e) {
577:                 failure = e;
578:             }
579:         }
580:         throw new NoSuchAlgorithmException
581:             ("Cannot find any provider supporting " + transformation, failure);
582:     }
